module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
    // TODO: Please fill in your logic design here
    // Declare internal signals
    reg [7:0] cnt;
    reg [1:0] state;
    reg p_red, p_yellow, p_green;
    // State transition logic
    always @(*) begin
        case (state)
            2'b00: begin // idle
                // Set all signals to 0
                p_red = 0;
                p_yellow = 0;
                p_green = 0;
                state = 2'b01;
            end
            2'b01: begin // s1_red
                // Set red signal to 1
                p_red = 1;
                p_yellow = 0;
                p_green = 0;
                if (cnt == 3) begin
                    state = 2'b11;
                end
                else begin
                    state = 2'b01;
                end
            end
            2'b10: begin // s2_yellow
                // Set yellow signal to 1
                p_red = 0;
                p_yellow = 1;
                p_green = 0;
                if (cnt == 3) begin
                    state = 2'b01;
                end
                else begin
                    state = 2'b10;
                end
            end
            2'b11: begin // s3_green
                // Set green signal to 1
                p_red = 0;
                p_yellow = 0;
                p_green = 1;
                if (cnt == 3) begin
                    state = 2'b10;
                end
                else begin
                    state = 2'b11;
                end
            end
        endcase
    end
    // Counter logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 10;
        end
        else if (pass_request && green) begin
            cnt <= 10;
        end
        else if (!green && p_green) begin
            cnt <= 60;
        end
        else if (!yellow && p_yellow) begin
            cnt <= 5;
        end
        else if (!red && p_red) begin
            cnt <= 10;
        end
        else begin
            cnt <= cnt - 1;
        end
    end
    // Output assignment
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            red <= 0;
            yellow <= 0;
            green <= 0;
        end
        else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end
    assign clock = cnt;
endmodule
